def calculate_quality_score(fact: str, source_count: int, recency_days: int) -> float:
    base = 0.5
    if source_count > 1:
        base += min(source_count * 0.1, 0.3)
    if recency_days < 7:
        base += 0.2
    elif recency_days < 30:
        base += 0.1
    return min(base, 1.0)
